import novamind_api as nm

# Check insights for S2 and S3 to see if we could serve them
s2 = nm.market.get_group_insights(group_id="S2")
s3 = nm.market.get_group_insights(group_id="S3")

print("=== S2 Insights ===")
for k, v in s2.items():
    if k != 'estimates':
        print(f"  {k}: {v}")
    else:
        for ek, ev in v.items():
            print(f"  {ek}: {ev}")

print("\n=== S3 Insights ===")
for k, v in s3.items():
    if k != 'estimates':
        print(f"  {k}: {v}")
    else:
        for ek, ev in v.items():
            print(f"  {ek}: {ev}")

# Check D_E09 insights more carefully
de09 = nm.market.get_group_insights(group_id="D_E09")
print("\n=== D_E09 Insights ===")
for k, v in de09.items():
    if k != 'estimates':
        print(f"  {k}: {v}")
    else:
        for ek, ev in v.items():
            print(f"  {ek}: {ev}")

# Calculate what quality we'd need for S2, S3
print("\n=== Serviceability Analysis ===")
